#include <stdio.h>
#include <string.h>
#include <stdint.h>

int charValue(char c){
    if(c>='0' && c<='9') return c-'0';
    return c-'a'+10;
}

uint64_t toVal(const char *s, int base){
    uint64_t v=0;
    for(; *s; ++s){
        v = v*base + charValue(*s);
    }
    return v;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    char line[30];
    int answer=0;
    for(int t=0;t<T;++t){
        scanf("%s",line);
        char *p1=strchr(line,'+');
        char *p2=strchr(line,'=');
        *p1='\0'; *p2='\0';
        char *A=line, *B=p1+1, *C=p2+1;
        int maxd=0;
        for(char *s=A;*s;++s) maxd = maxd>charValue(*s)?maxd:charValue(*s);
        for(char *s=B;*s;++s) maxd = maxd>charValue(*s)?maxd:charValue(*s);
        for(char *s=C;*s;++s) maxd = maxd>charValue(*s)?maxd:charValue(*s);
        int minBase = maxd+1; if(minBase<2) minBase=2;
        int ok=0;
        for(int base=minBase; base<=16 && !ok; ++base){
            uint64_t a=toVal(A,base), b=toVal(B,base), c=toVal(C,base);
            if(a+b==c) ok=1;
        }
        answer+=ok;
    }
    printf("%d\n",answer);
    return 0;
}

