#include <bits/stdc++.h>
using namespace std;

int charVal(char c){
    if(c>='0' && c<='9') return c-'0';
    return c-'a'+10;
}

unsigned long long toVal(const string &s, int base){
    unsigned long long v=0;
    for(char c: s) v = v*base + charVal(c);
    return v;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    string stmt; long long ans=0;
    while(T--){
        cin>>stmt;
        size_t p1=stmt.find('+');
        size_t p2=stmt.find('=');
        string A=stmt.substr(0,p1);
        string B=stmt.substr(p1+1,p2-p1-1);
        string C=stmt.substr(p2+1);
        int maxd=0;
        for(char c: A) maxd=max(maxd, charVal(c));
        for(char c: B) maxd=max(maxd, charVal(c));
        for(char c: C) maxd=max(maxd, charVal(c));
        int minBase=max(maxd+1,2);
        bool ok=false;
        for(int base=minBase; base<=16 && !ok; ++base){
            unsigned long long a=toVal(A,base);
            unsigned long long b=toVal(B,base);
            unsigned long long c=toVal(C,base);
            if(a+b==c) ok=true;
        }
        ans+=ok;
    }
    cout<<ans<<"\n";
    return 0;
}

