import java.io.*;
import java.util.*;

public class Main {
    private static int charVal(char c){
        if(c>='0' && c<='9') return c-'0';
        return c-'a'+10;
    }
    private static long toVal(String s, int base){
        long v=0;
        for(int i=0;i<s.length();i++) v = v*base + charVal(s.charAt(i));
        return v;
    }
    public static void main(String[] args) throws Exception{
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        long answer=0;
        for(int t=0;t<T;t++){
            String line = br.readLine().trim();
            int p1 = line.indexOf('+');
            int p2 = line.indexOf('=');
            String A = line.substring(0,p1);
            String B = line.substring(p1+1,p2);
            String C = line.substring(p2+1);
            int maxd=0;
            for(char c: A.toCharArray()) maxd = Math.max(maxd, charVal(c));
            for(char c: B.toCharArray()) maxd = Math.max(maxd, charVal(c));
            for(char c: C.toCharArray()) maxd = Math.max(maxd, charVal(c));
            int minBase = Math.max(maxd+1, 2);
            boolean ok=false;
            for(int base=minBase; base<=16 && !ok; base++){
                long a = toVal(A, base);
                long b = toVal(B, base);
                long c = toVal(C, base);
                if(a+b==c) ok=true;
            }
            if(ok) answer++;
        }
        System.out.println(answer);
    }
}

