import sys

def char_val(ch):
    if '0' <= ch <= '9':
        return ord(ch) - ord('0')
    return ord(ch) - ord('a') + 10

def to_val(s, base):
    v = 0
    for ch in s:
        v = v * base + char_val(ch)
    return v

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    ans = 0
    for i in range(1, T+1):
        stmt = data[i].strip()
        p1 = stmt.find('+')
        p2 = stmt.find('=')
        A = stmt[:p1]
        B = stmt[p1+1:p2]
        C = stmt[p2+1:]
        maxd = 0
        for ch in A+B+C:
            v = char_val(ch)
            if v > maxd:
                maxd = v
        min_base = max(maxd + 1, 2)
        ok = False
        for base in range(min_base, 17):
            if to_val(A, base) + to_val(B, base) == to_val(C, base):
                ok = True
                break
        if ok:
            ans += 1
    print(ans)

if __name__ == "__main__":
    solve()

